static Document parseByteData(ByteBuffer byteData, String charsetName, String baseUri, Parser parser) {
        String docData;
        Document doc = null;
        if (charsetName == null) { // determine from meta. safe parse as UTF-8
            // look for <meta http-equiv="Content-Type" content="text/html;charset=gb2312"> or HTML5 <meta charset="gb2312">
            docData = Charset.forName(defaultCharset).decode(byteData).toString();
            doc = parser.parseInput(docData, baseUri);
            Element meta = doc.select("meta[http-equiv=content-type], meta[charset]").first();
            if (meta != null) { // if not found, will keep utf-8 as best attempt

                String foundCharset;
                if (meta.hasAttr("http-equiv")) {
                    foundCharset = getCharsetFromContentType(meta.attr("content"));
                } else {
                    foundCharset = meta.attr("charset");
                    if (foundCharset != null) {
                        foundCharset = foundCharset.trim();
                        // strip surrounding quotes if any (including broken trailing or leading)
                        if (foundCharset.length() > 0) {
                            char first = foundCharset.charAt(0);
                            if (first == '"' || first == '\'')
                                foundCharset = foundCharset.substring(1);
                        }
                        if (foundCharset.length() > 0) {
                            char last = foundCharset.charAt(foundCharset.length() - 1);
                            if (last == '"' || last == '\'')
                                foundCharset = foundCharset.substring(0, foundCharset.length() - 1);
                        }
                        // if contains multiple, take the first
                        int comma = foundCharset.indexOf(',');
                        if (comma != -1)
                            foundCharset = foundCharset.substring(0, comma).trim();
                        // handle accidental duplicate prefix
                        String lc = foundCharset.toLowerCase(Locale.ENGLISH);
                        while (lc.startsWith("charset=")) {
                            foundCharset = foundCharset.substring(8).trim();
                            lc = foundCharset.toLowerCase(Locale.ENGLISH);
                        }
                        if (foundCharset.length() == 0 || !Charset.isSupported(foundCharset))
                            foundCharset = null;
                    }
                }

                if (foundCharset != null && foundCharset.length() != 0 && !foundCharset.equals(defaultCharset)) { // need to re-decode
                    charsetName = foundCharset;
                    byteData.rewind();
                    docData = Charset.forName(foundCharset).decode(byteData).toString();
                    doc = null;
                }
            }
        } else { // specified by content type header (or by user on file load)
            Validate.notEmpty(charsetName, "Must set charset arg to character set of file to parse. Set to null to attempt to detect from HTML");
            docData = Charset.forName(charsetName).decode(byteData).toString();
        }
        if (doc == null) {
            // there are times where there is a spurious byte-order-mark at the start of the text. Shouldn't be present
            // in utf-8. If after decoding, there is a BOM, strip it; otherwise will cause the parser to go straight
            // into head mode
            if (docData.length() > 0 && docData.charAt(0) == 65279)
                docData = docData.substring(1);

            doc = parser.parseInput(docData, baseUri);
            doc.outputSettings().charset(charsetName);
        }
        return doc;
    }

static String getCharsetFromContentType(String contentType) {
        if (contentType == null) return null;
        Matcher m = charsetPattern.matcher(contentType);
        if (m.find()) {
            String charset = m.group(1).trim();
            // take first if multiple separated by comma
            int comma = charset.indexOf(',');
            if (comma != -1)
                charset = charset.substring(0, comma).trim();
            // handle duplicate prefix like charset=charset=iso-8859-1
            String lc = charset.toLowerCase(Locale.ENGLISH);
            while (lc.startsWith("charset=")) {
                charset = charset.substring(8).trim();
                lc = charset.toLowerCase(Locale.ENGLISH);
            }
            // strip surrounding quotes if present
            if (charset.length() > 0) {
                char first = charset.charAt(0);
                if (first == '"' || first == '\'')
                    charset = charset.substring(1);
            }
            if (charset.length() > 0) {
                char last = charset.charAt(charset.length() - 1);
                if (last == '"' || last == '\'')
                    charset = charset.substring(0, charset.length() - 1);
            }
            if (charset.length() == 0) return null;
            if (Charset.isSupported(charset)) return charset;
            String upper = charset.toUpperCase(Locale.ENGLISH);
            if (Charset.isSupported(upper)) return upper;
            // if our advanced charset matching fails.... we just take the default
        }
        return null;
    }
